import{c as e,i as t,n,o as r,r as i,s as a,t as o}from"./app-BLsmuJVH.js";var s=JSON.parse(`{"path":"/mindscape.html","title":"Mindscape 🔥","lang":"ko-KR","frontmatter":{"description":"Mindscape 🔥 Main Logo KeyBaseZone은 ‘핵심(Key)’, ‘기반(Base)’, ‘영역(Zone)’이라는 세 가지 개념이 교차하는 지점에서 탄생한 지식 기반 blog이다. 이 이름은 단순한 영문 조합이 아닌, 사유 구조와 창작 철학, 그리고 정체성에 대한 해석을 담고 있으며, 창의적으로 재구...","permalink":"/mindscape","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Mindscape 🔥\\",\\"image\\":[\\"https://kmbzn.com/images/og.png\\"],\\"dateModified\\":\\"2026-06-12T15:12:24.000Z\\",\\"author\\":[]}"],["meta",{"property":"og:url","content":"https://kmbzn.com/mindscape"}],["meta",{"property":"og:title","content":"Mindscape 🔥"}],["meta",{"property":"og:description","content":"Mindscape 🔥 Main Logo KeyBaseZone은 ‘핵심(Key)’, ‘기반(Base)’, ‘영역(Zone)’이라는 세 가지 개념이 교차하는 지점에서 탄생한 지식 기반 blog이다. 이 이름은 단순한 영문 조합이 아닌, 사유 구조와 창작 철학, 그리고 정체성에 대한 해석을 담고 있으며, 창의적으로 재구..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://kmbzn.com/images/og.png"}],["meta",{"property":"og:locale","content":"ko-KR"}],["meta",{"property":"og:updated_time","content":"2026-06-12T15:12:24.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-12T15:12:24.000Z"}]]},"git":{"createdTime":1747767298000,"updatedTime":1781277144000,"contributors":[{"name":"김병준","username":"","email":"kmbzn24@hanyang.ac.kr","commits":4},{"name":"kmbzn","username":"kmbzn","email":"kmbzn24@gmail.com","commits":3,"url":"https://github.com/kmbzn"},{"name":"Claude Sonnet 4.6","username":"","email":"noreply@anthropic.com","commits":1}],"changelog":[{"hash":"867901d169b73496a8a67d2853b6d0b27bdbf876","time":1781277144000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"docs: rename all files to lowercase and add Products/Finance articles","coAuthors":[{"name":"Claude Sonnet 4.6","email":"noreply@anthropic.com"}]},{"hash":"9dec6af446516dac86f26db73b1d3156fcfcb0f0","time":1767129362000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"Add documentation for Winemoji font and Nasal Irrigation technique"},{"hash":"eb48cfa19b19a2f50f39f47a7af1731ebae06859","time":1760995141000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"Add requirements elicitation and architecture documentation"},{"hash":"36c74d53c5728d815386132c158a9a67852189ea","time":1748037538000,"email":"kmbzn24@hanyang.ac.kr","author":"김병준","message":"update musics"},{"hash":"18b0a1389c4a08eb46973def3af804e89ce05d22","time":1748027266000,"email":"kmbzn24@hanyang.ac.kr","author":"김병준","message":"update main"},{"hash":"9461eff95217532807b27aee343d788c87a82af8","time":1747871687000,"email":"kmbzn24@hanyang.ac.kr","author":"김병준","message":"add operating-system"},{"hash":"1bbd07a9cb61b1f14627ae7180ba26cf4844352b","time":1747767298000,"email":"kmbzn24@hanyang.ac.kr","author":"김병준","message":"og image update"}]},"filePathRelative":"mindscape.md","autoDesc":true}`),c={name:`mindscape.md`},l={class:`print-section`};function u(o,s,c,u,d,f){let p=e(`DateMeta`);return a(),i(`div`,null,[n(`section`,l,[s[0]||=n(`h1`,{id:`mindscape-🔥`,tabindex:`-1`},[n(`a`,{class:`header-anchor`,href:`#mindscape-🔥`},[n(`span`,null,`Mindscape 🔥`)])],-1),r(p),s[1]||=t(`<p align="center"><img src="https://kmbzn.com/images/android-chrome-512x512.png" width="180" alt="Main Logo"></p><p><strong>KeyBaseZone</strong>은 ‘핵심(Key)’, ‘기반(Base)’, ‘영역(Zone)’이라는 세 가지 개념이 교차하는 지점에서 탄생한 지식 기반 blog이다. 이 이름은 단순한 영문 조합이 아닌, 사유 구조와 창작 철학, 그리고 정체성에 대한 해석을 담고 있으며, 창의적으로 재구성된 약어 <strong>KBZ</strong>를 통해 고유한 의미 체계를 구축한다.</p><hr><p><strong>Key</strong>는 문제를 여는 열쇠이자 복잡한 개념을 관통하는 핵심을 상징한다. 기술적 주제, 철학적 사유, 디자인적 직관 등 다양한 분야의 본질을 파고드는 태도를 통해 KeyBaseZone은 하나의 해결 지향적 사고 공간으로 기능한다. 여기서 Key는 단순한 정보의 나열이 아닌, 지식 구조 속에서 중요한 <strong>연결 고리이자 진입점</strong>으로 작용한다.</p><hr><p><strong>Base</strong>는 축적된 지식의 기반이자 사유의 근원이다. 수많은 정보가 쌓여가는 과정 속에서 그 자체가 정리되고 해석되며 새로운 인사이트로 전환된다. 이 기반은 단단한 구조를 지향하며, 불필요한 군더더기를 제거한 사고의 뼈대 위에 콘텐츠를 확립한다. 나아가 &#39;Base&#39;는 개발자 및 창작자 커뮤니티에서 익숙한 개념인 코드 저장소의 metaphor로도 작동하며, 기술적 정체성과 실천의 장으로 확장된다.</p><hr><p><strong>Zone</strong>은 사고와 창작이 자유롭게 이루어지는 몰입의 공간이자, 경계 없이 누구에게나 열린 지식의 광장이다. 이는 단순한 게시 공간을 넘어서, 주제 간 경계가 해체되고 서로 충돌하고 교차하는 융합적 환경으로 정의된다. 이 공간은 하나의 주제에 갇히지 않고 다양한 분야가 유기적으로 연결되는 구역이다. Zone은 곧 표현의 확장 영역이며, 모든 이의 사유가 자유롭게 머물고 교차하는 지점에서 시너지를 발휘하는 다층적 구조의 장(場)이다.</p><hr><p><strong>KeyBaseZone</strong>은 따라서 특정 주제에 국한된 기술 blog가 아니라, 핵심을 중심으로 구조화된 지식과 자율적 사유가 교차하는 <strong>정체성 기반의 지식 생태계</strong>로서 기능한다. <strong>KBZ</strong>라는 약어는 본래의 이니셜에서 출발하되, 의도적인 치환을 통해 고유한 기호로 탈바꿈된다. 이는 기존의 자기 정의를 고수하는 대신, 스스로 재해석하고 확장 가능한 정체성으로 전환하려는 시도를 상징한다.</p><hr><p>궁극적으로 <strong>KeyBaseZone</strong>은 <strong>핵심적 사유(Key)</strong>, <strong>구조화된 기반(Base)</strong>, <strong>다층적 표현의 공간(Zone)</strong> 을 융합하여 콘텐츠가 탄생하고 순환하며 진화하는 독립적인 지식 기반 시스템이다. 이것은 단순한 아카이브가 아닌, 끊임없는 구조화와 탈구조화, 탐색과 재구성을 통해 정체성을 만들어가는 철학적 실천의 장이자, 창의적 사고의 흐름이 멈추지 않는 하나의 <strong>확장된 지성 공간</strong>이다.</p>`,12)])])}var d=o(c,[[`render`,u]]);export{s as _pageData,d as default};